(function (){'use strict';if (typeof window==='undefined') return;const TIMEOUT_MS=5000;function getSiteKey(){const meta=document.querySelector('meta[name="recaptcha-site-key"]');if (meta&&meta.content) return meta.content.trim();if (window.__RECAPTCHA_SITE_KEY) return window.__RECAPTCHA_SITE_KEY;return '';}function waitForGrecaptcha(timeoutMs){return new Promise((resolve)=>{if (window.grecaptcha&&window.grecaptcha.execute){if (window.grecaptcha.ready){window.grecaptcha.ready(()=>resolve(true));}else{resolve(true);}return;}const start=Date.now();const tick=()=>{if (window.grecaptcha&&window.grecaptcha.execute){if (window.grecaptcha.ready){window.grecaptcha.ready(()=>resolve(true));}else{resolve(true);}return;}if (Date.now()-start>timeoutMs) return resolve(false);setTimeout(tick,100);};tick();});}window.getRecaptchaToken=async function (action){const siteKey=getSiteKey();if (!siteKey) return '';try{const ready=await waitForGrecaptcha(TIMEOUT_MS);if (!ready) return '';const token=await window.grecaptcha.execute(siteKey,{action:action||'submit'});return typeof token==='string' ? token:'';}catch (err){return '';}};})();